void solve(int CASE)
{
	int n; cin >> n;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		u++, v++;
		g[u].pb(v), g[v].pb(u);
	}

	var lca = MT::LCA(n, g);
	var siz = vector<ll>(n + 1);
	var dfs = [&](var dfs, int now, int fa)->void {
		siz[now] = 1;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			siz[now] += siz[to];
		}
		};
	dfs(dfs, 1, 0);

	ll ans = 0;
	int x = 1, y = 1, xzhi = 1; // 链的两个端点 x，y; x 端点进入的一个子树 xzhi
	ll now = 1, last = 0;       // 当前链的 mex，之前链的 mex
	var vis = vector<bool>(n + 1);
	vis[1] = 1;
	while (now != n + 1) {

		if (x == y) {
			for (int to : g[x])ans += siz[to] * (siz[x] - siz[to] - 1) * (now - last);
			ans /= 2;
			ans += siz[1] * (now - last);
		}
		else {
			if (y == 1)ans += siz[x] * (siz[y] - siz[xzhi]) * (now - last);
			else ans += siz[x] * siz[y] * (now - last);
		}

		if (now == n)break;

		if (lca.lca(x, now + 1) == x and lca.lca(y, now + 1) == 1) {

			// 预期 now += 1
			int cur = now + 1;
			while (cur != x) {
				vis[cur] = 1;
				if (lca.f[cur][0] == 1)xzhi = cur; // x 端点进的第一个子树的编号
				cur = lca.f[cur][0];
			}

			// 更新 now
			last = now;
			fa(i, last + 1, n) {
				if (vis[i])now = i;
				else break;
			}
			x = last + 1;
		}
		else if (lca.lca(y, now + 1) == y and lca.lca(x, now + 1) == 1) {

			// 预期 now += 1
			int cur = now + 1;
			while (cur != y) {
				vis[cur] = 1;
				cur = lca.f[cur][0];
			}

			// 更新 now
			last = now;
			fa(i, last + 1, n) {
				if (vis[i])now = i;
				else break;
			}
			y = last + 1;
		}
		else break;
	}
	cout << ans << endl;
	return;
}
